    async def get_track(self, track_id: str, **kwargs: Any) -> Optional[GetTrackTrack]:
        query = gql("""
            query GetTrack($trackId: String!) {
              track(trackId: $trackId) {
                id
                title
                ISRC
                diskInfo {
                  diskNumber
                  trackNumber
                }
                duration
                isExplicit
                isAtmos
                releaseDate
                album {
                  id
                  displayTitle
                  cover {
                    id
                    urls(pictureRequest: {width: 1000, height: 1000})
                  }
                }
                contributors(first: 50, roles: [MAIN, FEATURED]) {
                  edges {
                    roles
                    node {
                      __typename
                      ... on Artist {
                        id
                        name
                      }
                    }
                  }
                }
                media {
                  id
                  version
                  token {
                    payload
                    expiresAt
                  }
                  estimatedSizes {
                    MP3_MISC
                    MP3_128
                    MP3_320
                    FLAC
                  }
                  rights {
                    ads {
                      available
                    }
                    sub {
                      available
                    }
                  }
                }
                lyrics {
                  synchronizedLines {
                    lrcTimestamp
                    line
                    milliseconds
                    duration
                  }
                  text
                  copyright
                  writers
                }
                isFavorite
              }
            }
            """)
        variables: dict[str, object] = {"trackId": track_id}
        response = await self.execute(
            query=query, operation_name="GetTrack", variables=variables, **kwargs
        )
        data = self.get_data(response)
        return GetTrack.model_validate(data).track

